package perfbenchcmd

import (
	"bufio"
	"fmt"
	"math/rand"
	"os"
	"path/filepath"

	"github.com/qiangli/coreutils/tool"
)

// runGen materializes the deterministic benchmark corpus into ./corpus (under
// rc.Dir). The generator + its seed are committed; the generated BYTES are
// gitignored (they are large and reproducible). Same corpus feeds both the perf
// datasets and the conformance fixtures, so both arms see identical inputs.
//
// Seed is fixed so runs are reproducible; do NOT read a wall clock (a run must
// reproduce byte-for-byte across machines and dates). Value fits int64.
const corpusSeed int64 = 0x2545F4914F6CDD1D

func runGen(rc *tool.RunContext, args []string) int {
	_ = args // TODO: --dir, --sizes, --seed overrides
	dir := rc.Path("corpus")
	if err := os.MkdirAll(dir, 0o755); err != nil {
		fmt.Fprintln(rc.Err, "perfbench gen:", err)
		return 1
	}
	rng := rand.New(rand.NewSource(corpusSeed))

	// 1) line files at 1e3 / 1e5 / 1e6 lines (varied width) — for sort/wc/grep/cut/uniq.
	for _, n := range []int{1_000, 100_000, 1_000_000} {
		name := filepath.Join(dir, fmt.Sprintf("lines-%d.txt", n))
		if err := genLines(name, n, rng); err != nil {
			fmt.Fprintln(rc.Err, "perfbench gen:", err)
			return 1
		}
	}
	// alias the 1e6 file to the name builtinWorkloads/builtinCases expect
	_ = os.Remove(filepath.Join(dir, "lines-1e6.txt"))
	_ = os.Symlink("lines-1000000.txt", filepath.Join(dir, "lines-1e6.txt"))

	// 2) directory trees for find/du/cp/grep -r/ls -R.
	//    wide-shallow, deep-narrow, many-small — TODO: parameterize sizes.
	if err := genTree(filepath.Join(dir, "tree-wide"), 4, 500, rng); err != nil { // depth 4, ~500 files/level
		fmt.Fprintln(rc.Err, "perfbench gen:", err)
		return 1
	}
	// TODO: genTree deep-narrow (depth 20, 2/level), many-small (10k tiny files),
	//       few-large (a handful of 100MB files) — see spec §5.4.

	// 3) small, hand-authored, byte-exact fixtures for the FIDELITY matrix
	//    (cases.go). Deterministic constants — no RNG — so both arms diff cleanly.
	if err := genConf(filepath.Join(dir, "conf")); err != nil {
		fmt.Fprintln(rc.Err, "perfbench gen:", err)
		return 1
	}

	fmt.Fprintf(rc.Out, "corpus generated under %s (seed %#x)\n", dir, uint64(corpusSeed))
	return 0
}

// conf fixture contents — exact bytes, referenced by cases.go via the f* consts.
const (
	confText = "Hello World\n" +
		"hello world\n" +
		"apple\n" +
		"Banana\n" +
		"apple\n" +
		"cherry pie\n" +
		"  leading\n" +
		"tab\there\n" +
		"MixedCASE 42\n" +
		"trailing   \n" +
		"\n" +
		"\n" +
		"last\n"
	confNums   = "10\n2\n33\n4\n100\n5\n-7\n"
	confFields = "3\tcharlie\t30\n1\talpha\t10\n2\tbravo\t20\n10\tdelta\t40\n"
	confDups   = "apple\napple\nbanana\nbanana\nbanana\ncherry\n"
)

func genConf(dir string) error {
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return err
	}
	for name, body := range map[string]string{
		"text.txt": confText, "nums.txt": confNums,
		"fields.tsv": confFields, "dups.txt": confDups,
		// sorted pair for comm; keyed pair for join
		"comm_a.txt": "apple\nbanana\ncherry\n",
		"comm_b.txt": "banana\ncherry\ndate\n",
		"join_a.txt": "1 alpha\n2 bravo\n3 charlie\n",
		"join_b.txt": "1 one\n2 two\n4 four\n",
		// tsort DAG (edges); paste columns
		"dag.txt": "a b\nb c\na c\n",
	} {
		if err := os.WriteFile(filepath.Join(dir, name), []byte(body), 0o644); err != nil {
			return err
		}
	}
	// a symlink for readlink/realpath (idempotent across reruns)
	link := filepath.Join(dir, "link_to_text")
	_ = os.Remove(link)
	if err := os.Symlink("text.txt", link); err != nil {
		return err
	}
	return nil
}

// genLines writes n lines of pseudo-log text: "<TS> <LEVEL> <token> <token>...".
// ~1 in 10 lines contains "ERROR" so grep/uniq -c workloads have real matches.
func genLines(path string, n int, rng *rand.Rand) error {
	f, err := os.Create(path)
	if err != nil {
		return err
	}
	defer f.Close()
	w := bufio.NewWriterSize(f, 1<<20)
	defer w.Flush()

	levels := []string{"INFO", "WARN", "ERROR", "DEBUG", "TRACE"}
	for i := 0; i < n; i++ {
		lvl := levels[rng.Intn(len(levels))]
		if rng.Intn(10) == 0 {
			lvl = "ERROR"
		}
		width := 3 + rng.Intn(8) // varied line width
		fmt.Fprintf(w, "%010d %s", rng.Int63(), lvl)
		for j := 0; j < width; j++ {
			fmt.Fprintf(w, " tok%d", rng.Intn(1000))
		}
		w.WriteByte('\n')
	}
	return nil
}

// genTree writes a directory tree: `fanout` files + subdirs per level, `depth` deep.
func genTree(root string, depth, fanout int, rng *rand.Rand) error {
	if depth == 0 {
		return nil
	}
	if err := os.MkdirAll(root, 0o755); err != nil {
		return err
	}
	for i := 0; i < fanout; i++ {
		fp := filepath.Join(root, fmt.Sprintf("f%04d.txt", i))
		body := fmt.Sprintf("file %d level %d\nERROR maybe %d\n", i, depth, rng.Intn(100))
		if err := os.WriteFile(fp, []byte(body), 0o644); err != nil {
			return err
		}
	}
	// one subdir carries the tree deeper (keeps total bounded); widen as needed.
	return genTree(filepath.Join(root, "sub"), depth-1, fanout, rng)
}
